uniform float tolerance : hint_range(0.0, 1.0) = 0.18;
void fragment() { vec4 tex = texture(TEXTURE, UV); float d = distance(tex.rgb, from_color.rgb); COLOR = d < tolerance ? vec4(to_color.rgb, tex.a) : tex; }

shader_type canvas_item;
uniform vec4 src1 : source_color = vec4(1,0,0,1); uniform vec4 src2 : source_color = vec4(0,1,0,1);
uniform vec4 src3 : source_color = vec4(0,0,1,1); uniform vec4 src4 : source_color = vec4(1,1,0,1);
uniform vec4 dst1 : source_color = vec4(0,0,0,1); uniform vec4 dst2 : source_color = vec4(0,0,0,1);
uniform vec4 dst3 : source_color = vec4(0,0,0,1); uniform vec4 dst4 : source_color = vec4(0,0,0,1);
uniform float tol : hint_range(0,1) = 0.1;
void fragment() { vec4 t = texture(TEXTURE,UV); COLOR=t;
if(distance(t.rgb,src1.rgb)<tol) COLOR=vec4(dst1.rgb,t.a);
else if(distance(t.rgb,src2.rgb)<tol) COLOR=vec4(dst2.rgb,t.a);
else if(distance(t.rgb,src3.rgb)<tol) COLOR=vec4(dst3.rgb,t.a);
else if(distance(t.rgb,src4.rgb)<tol) COLOR=vec4(dst4.rgb,t.a); }

