shader_type canvas_item;
uniform float scan_angle : hint_range(0,6.2832) = 0.0;
uniform vec4 scan_color : source_color = vec4(0.2,1,0.3,0.6);
void fragment() { vec4 t = texture(TEXTURE,UV); vec2 dir = UV-vec2(0.5); float a = atan(dir.y, dir.x)+3.14159; float sweep = 1.0-smoothstep(0.0,0.5,abs(a-scan_angle)); COLOR = vec4(mix(t.rgb, scan_color.rgb, sweep*scan_color.a), max(t.a, sweep*scan_color.a)); }

shader_type canvas_item;
