uniform float scanline_intensity : hint_range(0,1) = 0.3;
void fragment() { vec2 uv=UV*2.0-1.0; uv*=1.0+curvature*dot(uv,uv); uv=uv*0.5+0.5; if(uv.x<0.0||uv.x>1.0||uv.y<0.0||uv.y>1.0) COLOR=vec4(0,0,0,1); else { vec4 t=texture(TEXTURE,uv); float sl=sin(uv.y*400.0)*0.5+0.5; COLOR=vec4(mix(t.rgb,t.rgb*(0.7+sl*0.3),scanline_intensity),t.a); } }

shader_type canvas_item;
uniform float bloom_threshold : hint_range(0,1) = 0.7;
uniform float bloom_intensity : hint_range(0,2) = 0.5;
void fragment() { vec4 t=texture(TEXTURE,UV); float bright=max(t.r,max(t.g,t.b))-bloom_threshold; bright=clamp(bright,0.0,1.0)*bloom_intensity; COLOR=vec4(t.rgb+bright,t.a); }

shader_type canvas_item;
uniform float speed : hint_range(-5,5) = 1.0;
vec3 hsv2rgb(vec3 c){vec4 K=vec4(1,2.0/3.0,1.0/3.0,3);vec3 p=abs(fract(c.xxx+K.xyz)*6.0-K.www);return c.z*mix(K.xxx,clamp(p-K.xxx,0.0,1.0),c.y);}
vec3 rgb2hsv(vec3 c){vec4 K=vec4(0,-1.0/3.0,2.0/3.0,-1);vec4 p=mix(vec4(c.bg,K.wz),vec4(c.gb,K.xy),step(c.b,c.g));vec4 q=mix(vec4(p.xyw,c.r),vec4(c.r,p.yzx),step(p.x,c.r));float d=q.x-min(q.w,q.y);return vec3(abs(q.z+(q.w-q.y)/(6.0*d+0.001)),d/(q.x+0.001),q.x);}
void fragment(){vec4 t=texture(TEXTURE,UV);vec3 hsv=rgb2hsv(t.rgb);hsv.x=fract(hsv.x+TIME*speed*0.1);COLOR=vec4(hsv2rgb(hsv),t.a);}

shader_type canvas_item;
uniform float freeze_amount : hint_range(0,1) = 0.6;
void fragment(){vec4 t=texture(TEXTURE,UV);float n=sin(UV.x*30+TIME)*cos(UV.y*25-TIME);vec3 frost=t.rgb*0.3+vec3(0.4,0.6,0.9)*0.7+vec3(1,1,1)*n*0.15;COLOR=vec4(mix(t.rgb,frost,freeze_amount),t.a);}

shader_type canvas_item;
uniform float intensity : hint_range(0,2) = 0.7;
float noise(vec2 p){return fract(sin(dot(p,vec2(127.1,311.7)))*43758.5453);}
void fragment(){vec4 t=texture(TEXTURE,UV);float n=noise(floor(UV*vec2(16,24))+vec2(TIME*3,0));n+=noise(floor(UV*vec2(8,12))-vec2(TIME*2,0))*0.5;vec3 fire=mix(vec3(1,0.3,0),vec3(1,0.8,0.1),max(0,1-UV.y*2+n*0.5));COLOR=vec4(mix(t.rgb,fire*t.a,intensity*0.6*n),t.a);}

shader_type canvas_item;
uniform float crystal_intensity : hint_range(0,1) = 0.4;
void fragment(){vec4 t=texture(TEXTURE,UV);vec2 cp=fract(UV*8)-0.5;float hex=1-smoothstep(0.4,0.5,max(abs(cp.x)*1.2,abs(cp.y)));COLOR=vec4(mix(t.rgb,t.rgb*1.3+vec3(0.3,0.5,0.7),hex*crystal_intensity),t.a);}

shader_type canvas_item;
