shader_type canvas_item;
uniform float invert_amount : hint_range(0,1) = 1.0;
void fragment(){vec4 t=texture(TEXTURE,UV);COLOR=vec4(mix(t.rgb,1.0-t.rgb,invert_amount),t.a);}

shader_type canvas_item;
uniform float pixel_size : hint_range(1,64) = 4.0;
uniform vec2 texture_size = vec2(256,256);
void fragment(){vec2 ps=vec2(pixel_size)/texture_size;vec2 uv=floor(UV/ps)*ps+ps*0.5;COLOR=texture(TEXTURE,uv);}

shader_type canvas_item;
uniform float amplitude : hint_range(0,0.1)=0.015;
uniform float frequency : hint_range(1,30)=8.0;
uniform float speed : hint_range(-5,5)=2.0;
void fragment(){vec2 uv=UV;uv.x+=sin(uv.y*frequency+TIME*speed)*amplitude;COLOR=texture(TEXTURE,uv);}

shader_type canvas_item;
uniform float amplitude : hint_range(0,0.1)=0.015;
uniform float frequency : hint_range(1,30)=8.0;
uniform float speed : hint_range(-5,5)=2.0;
void fragment(){vec2 uv=UV;uv.y+=sin(uv.x*frequency+TIME*speed)*amplitude;COLOR=texture(TEXTURE,uv);}

shader_type canvas_item;
uniform float blur_amount : hint_range(0,0.1)=0.02;
uniform float samples : hint_range(4,32)=12.0;
void fragment(){vec4 col=vec4(0);vec2 d=UV-0.5;for(float i=0;i<samples;i++){float t=i/samples;col+=texture(TEXTURE,UV-d*t*blur_amount);}COLOR=col/samples;}

shader_type canvas_item;
uniform float amount : hint_range(0,2)=0.5;
uniform vec2 texture_size=vec2(256,256);
void fragment(){vec2 ps=1.0/texture_size;vec4 t=texture(TEXTURE,UV);vec4 blur=t*4;blur+=texture(TEXTURE,UV+vec2(-ps.x,0));blur+=texture(TEXTURE,UV+vec2(ps.x,0));blur+=texture(TEXTURE,UV+vec2(0,-ps.y));blur+=texture(TEXTURE,UV+vec2(0,ps.y));blur/=8.0;COLOR=mix(blur,t,1.0+amount);}

shader_type canvas_item;
uniform float strength : hint_range(0,2)=0.5;
uniform vec2 texture_size=vec2(256,256);
void fragment(){vec2 ps=1.0/texture_size;float tl=texture(TEXTURE,UV+vec2(-ps.x,-ps.y)).r;float br=texture(TEXTURE,UV+vec2(ps.x,ps.y)).r;float e=(tl-br)*strength+0.5;COLOR=vec4(e,e,e,1.0)*texture(TEXTURE,UV);}

shader_type canvas_item;
uniform vec2 blur_direction = vec2(1.0,0.0);
uniform float blur_strength : hint_range(0,0.1)=0.03;
uniform int samples : hint_range(4,32)=12;
void fragment(){vec4 col=vec4(0);vec2 dir=normalize(blur_direction)*blur_strength;for(int i=0;i<32;i++){if(i>=samples)break;float t=(float(i)-float(samples)/2.0)/float(samples);col+=texture(TEXTURE,UV+dir*t);}COLOR=col/float(samples);}

shader_type canvas_item;
uniform float threshold : hint_range(0,1)=0.3;
uniform vec2 texture_size=vec2(256,256);
void fragment(){vec2 ps=1.0/texture_size;float tl=luminance(texture(TEXTURE,UV+vec2(-ps.x,-ps.y)).rgb);float t=luminance(texture(TEXTURE,UV+vec2(0,-ps.y)).rgb);float tr=luminance(texture(TEXTURE,UV+vec2(ps.x,-ps.y)).rgb);float l=luminance(texture(TEXTURE,UV+vec2(-ps.x,0)).rgb);float r=luminance(texture(TEXTURE,UV+vec2(ps.x,0)).rgb);float bl=luminance(texture(TEXTURE,UV+vec2(-ps.x,ps.y)).rgb);float b=luminance(texture(TEXTURE,UV+vec2(0,ps.y)).rgb);float br=luminance(texture(TEXTURE,UV+vec2(ps.x,ps.y)).rgb);float gx=-tl-2*l-bl+tr+2*r+br;float gy=-tl-2*t-tr+bl+2*b+br;float e=sqrt(gx*gx+gy*gy);COLOR=vec4(vec3(e>threshold?1:0),1);}

shader_type canvas_item;
uniform float grain_amount : hint_range(0,0.3)=0.05;
float rand(vec2 p){return fract(sin(dot(p,vec2(127.1,311.7)))*43758.5453);}
void fragment(){vec4 t=texture(TEXTURE,UV);float n=rand(UV+TIME)*2.0-1.0;COLOR=vec4(t.rgb+n*grain_amount,t.a);}

shader_type canvas_item;
uniform vec2 scroll_speed = vec2(0.1,0.05);
void fragment(){vec2 uv=fract(UV+TIME*scroll_speed);COLOR=texture(TEXTURE,uv);}

shader_type canvas_item;
uniform float radius : hint_range(0,0.5)=0.1;
uniform vec2 texture_size=vec2(256,256);
void fragment(){vec2 rs=vec2(radius)/texture_size;vec2 uv=UV;float r=min(min(uv.x,1.0-uv.x)/rs.x,min(uv.y,1.0-uv.y)/rs.y);float alpha=smoothstep(0.0,1.0,clamp(r,0.0,1.0));vec4 t=texture(TEXTURE,UV);COLOR=vec4(t.rgb,t.a*alpha);}

shader_type canvas_item;
uniform float flash : hint_range(0,1)=0.0;
void fragment(){vec4 t=texture(TEXTURE,UV);COLOR=mix(t,vec4(1,1,1,1),flash);}

shader_type canvas_item;
uniform vec4 blend_color : source_color = vec4(0.5,0.3,0.1,1);
uniform float blend_amount : hint_range(0,1)=0.5;
void fragment(){vec4 t=texture(TEXTURE,UV);vec3 dodged=min(t.rgb/(1.0-blend_color.rgb+0.001),vec3(1.0));COLOR=vec4(mix(t.rgb,dodged,blend_amount),t.a);}

shader_type canvas_item;
uniform vec2 shadow_offset : source_color = vec2(0.008,0.008);
uniform vec4 shadow_color : source_color = vec4(0,0,0,0.5);
void fragment(){vec4 t=texture(TEXTURE,UV);float shadow_a=texture(TEXTURE,UV-shadow_offset).a;COLOR=vec4(mix(t.rgb,shadow_color.rgb,shadow_a*shadow_color.a*(1.0-t.a)),t.a+shadow_a*shadow_color.a*(1.0-t.a));}

shader_type canvas_item;
uniform vec2 light_pos = vec2(0.5,0.3);
uniform float intensity : hint_range(0,1)=0.3;
void fragment(){vec2 d=UV-light_pos;float dist=length(d);float flare=0.0;for(int i=1;i<=4;i++){float r=float(i)*0.15;flare+=exp(-pow((dist-r)/0.03,2.0))*0.5/float(i);}flare+=exp(-pow(dist/0.08,2.0))*2.0;COLOR=texture(TEXTURE,UV)+vec4(1,0.9,0.6,0)*flare*intensity;}

shader_type canvas_item;
uniform vec4 color_top : source_color = vec4(0,0,0,0.6);
uniform vec4 color_bottom : source_color = vec4(0,0,0,0);
void fragment(){vec4 t=texture(TEXTURE,UV);vec4 grad=mix(color_bottom,color_top,UV.y);COLOR=vec4(mix(t.rgb,grad.rgb,grad.a),t.a);}

shader_type canvas_item;
uniform float reflect_height : hint_range(0,1)=0.5;
uniform float reflect_alpha : hint_range(0,1)=0.3;
void fragment(){if(UV.y<reflect_height){COLOR=texture(TEXTURE,UV);}else{float ry=reflect_height-(UV.y-reflect_height);COLOR=texture(TEXTURE,vec2(UV.x,ry));COLOR.a*=reflect_alpha*(1.0-(UV.y-reflect_height)/(1.0-reflect_height)*0.5);}}

shader_type canvas_item;
uniform float strength : hint_range(-5,5)=1.0;
uniform float radius : hint_range(0,1)=0.5;
void fragment(){vec2 d=UV-0.5;float dist=length(d);float a=atan(d.y,d.x)+strength*(radius-dist)/radius;vec2 uv=0.5+vec2(cos(a),sin(a))*dist;COLOR=texture(TEXTURE,uv);}

shader_type canvas_item;
uniform int segments : hint_range(2,16)=6;
void fragment(){vec2 d=UV-0.5;float a=atan(d.y,d.x);float seg=TAU/float(segments);a=mod(a+seg*0.5,seg)-seg*0.5;vec2 uv=0.5+vec2(cos(a),sin(a))*length(d);COLOR=texture(TEXTURE,uv);}

shader_type canvas_item;
uniform float dither_amount : hint_range(0,1)=0.5;
float bayer(vec2 p){int x=int(mod(p.x,4.0));int y=int(mod(p.y,4.0));int m[16]={0,8,2,10,12,4,14,6,3,11,1,9,15,7,13,5};return float(m[y*4+x])/16.0;}
void fragment(){vec4 t=texture(TEXTURE,UV);float d=bayer(gl_FragCoord.xy);COLOR=vec4(floor(t.rgb*4.0+d*dither_amount)/4.0,t.a);}

shader_type canvas_item;
uniform int levels : hint_range(2,32)=6;
void fragment(){vec4 t=texture(TEXTURE,UV);COLOR=vec4(floor(t.rgb*float(levels))/float(levels-1),t.a);}

shader_type canvas_item;
uniform float threshold : hint_range(0,1)=0.5;
void fragment(){vec4 t=texture(TEXTURE,UV);vec3 s=mix(t.rgb,1.0-t.rgb,step(threshold,t.rgb));COLOR=vec4(s,t.a);}

shader_type canvas_item;
uniform float contrast : hint_range(0,3)=1.2;
uniform float brightness : hint_range(-1,1)=0.05;
void fragment(){vec4 t=texture(TEXTURE,UV);COLOR=vec4((t.rgb-0.5)*contrast+0.5+brightness,t.a);}

shader_type canvas_item;
uniform float saturation : hint_range(0,3)=1.5;
void fragment(){vec4 t=texture(TEXTURE,UV);float g=dot(t.rgb,vec3(0.299,0.587,0.114));COLOR=vec4(mix(vec3(g),t.rgb,saturation),t.a);}

shader_type canvas_item;
uniform float progress : hint_range(0,1) = 0.0;
uniform float edge_width : hint_range(0,0.5) = 0.1;
uniform vec4 edge_color : source_color = vec4(1.0,0.5,0.0,1.0);
uniform sampler2D noise_tex;
void fragment(){vec4 t=texture(TEXTURE,UV);float n=texture(noise_tex,UV).r;float threshold=smoothstep(progress-edge_width,progress+edge_width,n);vec4 edge=edge_color*(1.0-threshold)*smoothstep(progress-0.05,progress,n);COLOR=mix(vec4(0.0),t,threshold)+edge*edge_width*10.0;}

shader_type canvas_item;
uniform vec4 outline_color : source_color = vec4(0,0,0,1);
uniform float outline_width : hint_range(0,5) = 1.0;
uniform vec2 texture_size = vec2(256,256);
void fragment(){vec4 t=texture(TEXTURE,UV);vec2 ps=outline_width/texture_size;float a=texture(TEXTURE,UV+vec2(ps.x,0)).a+texture(TEXTURE,UV+vec2(-ps.x,0)).a+texture(TEXTURE,UV+vec2(0,ps.y)).a+texture(TEXTURE,UV+vec2(0,-ps.y)).a;COLOR=mix(vec4(outline_color.rgb,a*0.25),t,t.a);COLOR.a=max(t.a,a*0.25);}

shader_type canvas_item;
uniform float strength : hint_range(0,10) = 2.0;
void fragment(){vec2 uv=UV-0.5;float dist=length(uv);vec2 dir=normalize(uv);float s=dist*strength*0.01;vec4 r=texture(TEXTURE,UV+dir*s);vec4 g=texture(TEXTURE,UV);vec4 b=texture(TEXTURE,UV-dir*s);COLOR=vec4(r.r,g.g,b.b,max(max(r.a,g.a),b.a));}

shader_type canvas_item;
uniform float intensity : hint_range(0,1) = 0.5;
uniform float radius : hint_range(0,2) = 0.8;
void fragment(){vec4 t=texture(TEXTURE,UV);vec2 uv=UV-0.5;float d=length(uv)*2.0;float v=smoothstep(radius,radius-0.3,d);COLOR=vec4(t.rgb*mix(1.0,v,intensity),t.a);}

shader_type canvas_item;
uniform float strength : hint_range(0,1) = 0.1;
uniform float speed : hint_range(0,10) = 5.0;
float rand(vec2 c){return fract(sin(dot(c.xy,vec2(12.9898,78.233)))*43758.5453);}
void fragment(){vec2 uv=UV;float t=TIME*speed;float r=rand(vec2(floor(uv.y*50.0),t));if(r<strength){uv.x+=rand(vec2(floor(uv.y*30.0),t*2.0))*0.05-0.025;}float g=rand(vec2(floor(uv.y*40.0+5.0),t*1.5));if(g<strength*0.7){uv.x+=rand(vec2(floor(uv.y*25.0+10.0),t*3.0))*0.03-0.015;}vec4 c=texture(TEXTURE,uv);if(r<strength*0.3){c.r=texture(TEXTURE,uv+vec2(0.02,0)).r;c.b=texture(TEXTURE,uv+vec2(-0.02,0)).b;}COLOR=c;}

shader_type canvas_item;
uniform float strength : hint_range(0,0.1) = 0.02;
uniform float speed : hint_range(0,5) = 1.5;
uniform float base_y : hint_range(0,1) = 0.0;
void vertex(){float sway=sin(TIME*speed+VERTEX.x*0.05)*strength;float factor=smoothstep(base_y,1.0,UV.y);VERTEX.x+=sway*factor;}

shader_type canvas_item;
uniform float pixel_size : hint_range(1,64) = 4.0;
uniform vec2 texture_size = vec2(256,256);
void fragment(){vec2 px=vec2(pixel_size)/texture_size;vec2 uv=floor(UV/px)*px;COLOR=texture(TEXTURE,uv);}

shader_type canvas_item;
uniform float glow_intensity : hint_range(0,2) = 0.5;
uniform float glow_threshold : hint_range(0,1) = 0.7;
uniform vec2 texture_size = vec2(1920,1080);
void fragment(){vec4 c=texture(TEXTURE,UV);float bright=dot(c.rgb,vec3(0.299,0.587,0.114));if(bright>glow_threshold){vec2 ps=vec2(2.0)/texture_size;vec4 blur=texture(TEXTURE,UV+vec2(ps.x,0))+texture(TEXTURE,UV+vec2(-ps.x,0))+texture(TEXTURE,UV+vec2(0,ps.y))+texture(TEXTURE,UV+vec2(0,-ps.y));blur*=0.25;c+=blur*glow_intensity*(bright-glow_threshold);}COLOR=c;}

shader_type canvas_item;
uniform float freeze_amount : hint_range(0,1) = 0.5;
float rand(vec2 c){return fract(sin(dot(c,vec2(12.9898,78.233)))*43758.5453);}
void fragment(){vec4 t=texture(TEXTURE,UV);float n=rand(floor(UV*50.0+TIME))*0.3;vec3 ice=vec3(0.6,0.8,1.0);COLOR=vec4(mix(t.rgb,ice+n,freeze_amount*0.4),t.a);COLOR.rgb+=freeze_amount*0.1;}

shader_type canvas_item;
uniform float poison_amount : hint_range(0,1) = 0.5;
void fragment(){vec4 t=texture(TEXTURE,UV);float g=dot(t.rgb,vec3(0.299,0.587,0.114));vec3 poison=mix(t.rgb,vec3(g*0.5,g,g*0.4),0.5);COLOR=vec4(mix(t.rgb,poison,poison_amount),t.a);COLOR.rgb+=sin(TIME*3.0)*0.03*poison_amount;}
